import{_ as a,a as d,b as t,c as i,d as o,e as n,f as s,g as l}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as r,o as p,c,a2 as u}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"my/Other/federated-distributed-index.md","filePath":"my/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),h={name:"my/Other/federated-distributed-index.md"};function b(m,e,f,g,x,q){return p(),c("div",null,[...e[0]||(e[0]=[u('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index က ImgBed sites အများအပြားကို file lists တွေ အချင်းချင်း share လုပ်ခွင့်ပေးပါတယ်။</p><p>ရိုးရိုးပြောရရင်:</p><ul><li>သင့် site ထဲက selected folders တွေကိုအခြားသူများနဲ့ share လုပ်နိုင်ပါတယ်။</li><li>အခြား node တစ်ခုထဲ join လုပ်ပြီး အဲဒီ node ရဲ့ shared file list ကို သင့် admin panel ထဲ sync လုပ်နိုင်ပါတယ်။</li><li>Federated files တွေက browsing, searching, links ဖွင့်ခြင်းအတွက်အဓိကဖြစ်ပါတယ်။ သင့် storage ထဲကိုပြန် upload မလုပ်ပါ။</li></ul><h2 id="ဘယ်နေရာမှာ-configure-လုပ်မလဲ" tabindex="-1">ဘယ်နေရာမှာ Configure လုပ်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-configure-လုပ်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ Configure လုပ်မလဲ&quot;">​</a></h2><p>ဖွင့်ပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Local federation node" loading="lazy"></p><p>page မှာ tabs သုံးခုရှိပါတယ်:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>Local Node</td><td>သင့် node ကို enable လုပ်ရန်၊ public domain confirm လုပ်ရန်၊ shared folders ရွေးရန်၊ outbound index update လုပ်ရန်</td></tr><tr><td>Nodes I Joined</td><td>သင် joined ဖြစ်ထားတဲ့ အခြား ImgBed nodes တွေကို manage လုပ်ရန်</td></tr><tr><td>Nodes Joining Me</td><td>သင့် node ထဲ join ချင်တဲ့အခြားသူများရဲ့ requests တွေကို manage လုပ်ရန်</td></tr></tbody></table><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li><code>Local Node</code> ကိုဖွင့်ပါ။</li><li><code>Enable</code> ကို on လုပ်ပါ။</li><li><code>Sync folders</code> အောက်မှာ share လုပ်မယ့် folders ရွေးပါ။</li><li><code>Update Outbound Index</code> ကိုနှိပ်ပါ။</li><li>ImgBed က domain change detect လုပ်ရင် current domain မှန်ကန်ကြောင်း confirm လုပ်ပြီးမှဆက်ပါ။</li></ol><p>sync folders အများကြီးရွေးနိုင်ပါတယ်။</p><p>sync folder list ဗလာဖြစ်လျှင် folders အားလုံး share ဖြစ်ပါတယ်။</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>public domain ဆိုတာ အခြား nodes တွေက သင့် node ကို access လုပ်ဖို့သုံးတဲ့ site URL ဖြစ်ပါတယ်။</p><p>ImgBed ကဒါကို automatically detect လုပ်ပါတယ်။ manual type လုပ်စရာမလိုပါ။ index ကိုပထမဆုံး update လုပ်တဲ့အခါ current access URL က production domain ဟုတ်မဟုတ် ImgBed ကမေးပါမယ်။</p><p>နောက်ပိုင်း domains ပြောင်းလဲလျှင် index update က confirmation ထပ်မေးပါမယ်။</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders က federation nodes ဆီ ဘယ် files တွေ share ဖြစ်မလဲဆုံးဖြတ်ပါတယ်။</p><p>ဥပမာ သင်ရွေးထားတာ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>ဆိုရင် အခြား nodes တွေက အဲဒီ directories နှစ်ခုထဲက files တွေပဲမြင်နိုင်ပါမယ်။</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>ဒါက အခြား nodes တွေ သင့်ထံက sync လုပ်နိုင်တဲ့ file list ကို update လုပ်ပါတယ်။</p><p>ဒီအချိန်တွေမှာသုံးပါ:</p><ul><li>federation ကိုပထမဆုံး enable လုပ်တဲ့အခါ။</li><li>share လုပ်ချင်တဲ့ files upload လုပ်ပြီးနောက်။</li><li>sync folders ပြောင်းလဲတဲ့အခါ။</li><li>public domain ပြောင်းပြီး confirm လုပ်ရန်လိုတဲ့အခါ။</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> က အခြား nodes တွေကို subscribe လုပ်တဲ့နေရာဖြစ်ပါတယ်။</p><p><img src="`+d+'" alt="Nodes I joined" loading="lazy"></p><h3 id="အခြား-node-တစ်ခုထဲ-join-request-ပို့ခြင်း" tabindex="-1">အခြား Node တစ်ခုထဲ Join Request ပို့ခြင်း <a class="header-anchor" href="#အခြား-node-တစ်ခုထဲ-join-request-ပို့ခြင်း" aria-label="Permalink to &quot;အခြား Node တစ်ခုထဲ Join Request ပို့ခြင်း&quot;">​</a></h3><ol><li>အခြား owner ထံ invitation link တောင်းပါ။</li><li>input box ထဲ paste လုပ်ပါ။</li><li><code>Request to Join</code> ကိုနှိပ်ပါ။</li><li>အခြား owner က သူ့ admin panel မှာ approve လုပ်တာကိုစောင့်ပါ။</li></ol><p>approval ပြီးနောက် node status က approved ဖြစ်ပါမယ်။</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> က သင် joined ဖြစ်ထားတဲ့ nodes တွေမှ file lists sync လုပ်ပါတယ်။</p><p>ဒီအချိန်တွေမှာသုံးပါ:</p><ul><li>အခြား owner က သင့် request ကိုမကြာသေးခင် approve လုပ်ထားတဲ့အခါ။</li><li>shared content update ဖြစ်ပြီလို့ အခြား owner ကပြောတဲ့အခါ။</li><li>joined federation file lists အားလုံး refresh လုပ်ချင်တဲ့အခါ။</li></ul><p>node တစ်ခုတည်း update လုပ်ရန် အဲဒီ node card ပေါ်က <code>Update Index</code> ကိုနှိပ်ပါ။</p><p><img src="'+t+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>node တစ်ခုကို sync မလုပ်ချင်တော့လျှင် <code>Unsubscribe</code> ကိုနှိပ်ပါ။</p><p>unsubscribe ပြီးနောက် အဲဒီ node ရဲ့ federated index က သင့် local site ထဲကနေဖယ်ရှားပါမယ်။</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> က အခြားသူများထံက requests တွေကို handle လုပ်တဲ့နေရာဖြစ်ပါတယ်။</p><p><img src="'+i+'" alt="Nodes joining me" loading="lazy"></p><h3 id="invitation-link-ဖန်တီးခြင်း" tabindex="-1">Invitation Link ဖန်တီးခြင်း <a class="header-anchor" href="#invitation-link-ဖန်တီးခြင်း" aria-label="Permalink to &quot;Invitation Link ဖန်တီးခြင်း&quot;">​</a></h3><ol><li>local node enabled ဖြစ်ကြောင်းသေချာပါစေ။</li><li>ImgBed က public domain confirm လုပ်နိုင်အောင် <code>Update Outbound Index</code> ကိုအနည်းဆုံးတစ်ကြိမ်နှိပ်ပါ။</li><li><code>Nodes Joining Me</code> ကိုဖွင့်ပါ။</li><li><code>Reset Invitation Link</code> ကိုနှိပ်ပါ။</li><li>invitation link ကို copy လုပ်ပြီး အခြား owner ဆီပို့ပါ။</li></ol><p>invitation link ဗလာဖြစ်လျှင် public domain မ confirm လုပ်ရသေးတာဖြစ်နိုင်ပါတယ်။ <code>Local Node</code> ကိုပြန်သွားပြီး <code>Update Outbound Index</code> နှိပ်ပါ။</p><h3 id="join-requests-handle-လုပ်ခြင်း" tabindex="-1">Join Requests Handle လုပ်ခြင်း <a class="header-anchor" href="#join-requests-handle-လုပ်ခြင်း" aria-label="Permalink to &quot;Join Requests Handle လုပ်ခြင်း&quot;">​</a></h3><p>တစ်ယောက်ယောက် request submit လုပ်တဲ့အခါ <code>Nodes Joining Me</code> list ထဲပေါ်လာပါမယ်။</p><table tabindex="0"><thead><tr><th>Action</th><th>Meaning</th></tr></thead><tbody><tr><td>Approve</td><td>အခြား node ကို သင့် shared file list sync လုပ်ခွင့်ပေးသည်</td></tr><tr><td>Reject</td><td>join request ကိုငြင်းသည်</td></tr><tr><td>Delete</td><td>ပြီးဆုံးပြီး record ကိုဖယ်ရှားသည်</td></tr><tr><td>Check Status</td><td>အခြားဘက်မှာ ဒီ relationship ကိုဆက်ထားလားစစ်သည်</td></tr></tbody></table><p>approval ပြီးနောက် အခြားဘက်မှာ သင့် shared files ပေါ်ဖို့ <code>Update Inbound Index</code> ကိုနှိပ်ဖို့လိုပါသေးတယ်။</p><p><img src="'+o+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>relationship approved ဖြစ်ပြီးနောက် node card ပေါ်က <code>Message</code> ကိုနှိပ်ပါ။</p><p>Messages တွေက federation relationship အကြောင်းဆက်သွယ်ရေးအတွက်ပဲဖြစ်ပါတယ်။ files, tags, directories, permissions မပြောင်းပါ။</p><p><img src="'+n+'" alt="Messages" loading="lazy"></p><h2 id="federated-files-ကြည့်ခြင်း" tabindex="-1">Federated Files ကြည့်ခြင်း <a class="header-anchor" href="#federated-files-ကြည့်ခြင်း" aria-label="Permalink to &quot;Federated Files ကြည့်ခြင်း&quot;">​</a></h2><p>sync ပြီးနောက် admin file list ကိုပြန်သွားပါ။</p><p>page အပေါ်ပိုင်းမှာ local files နဲ့ federated files အကြား switch လုပ်ပါ။ federated files ထဲမှာ synced content ကို browse လုပ်နိုင်ပါတယ်။</p><p>Federated files တွေက viewing, searching, preview, links copy လုပ်ရန်အဓိကဖြစ်ပါတယ်။ local files မဟုတ်တဲ့အတွက် သင့် site မှ move, delete, retag, backup မလုပ်နိုင်ပါ။</p><p><img src="'+s+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="relationship-record-မရှိလို့-reapply-လုပ်ခိုင်းတာဘာကြောင့်လဲ" tabindex="-1">Relationship Record မရှိလို့ Reapply လုပ်ခိုင်းတာဘာကြောင့်လဲ? <a class="header-anchor" href="#relationship-record-မရှိလို့-reapply-လုပ်ခိုင်းတာဘာကြောင့်လဲ" aria-label="Permalink to &quot;Relationship Record မရှိလို့ Reapply လုပ်ခိုင်းတာဘာကြောင့်လဲ?&quot;">​</a></h3><p>များသောအားဖြင့် အခြားဘက်က သင့်ကို delete လုပ်ပြီး record ကိုဖယ်ရှားထားတာဖြစ်ပါတယ်။ relationship မတွေ့တော့တာပါ။ join request အသစ် submit လုပ်ပါ။</p><p><img src="'+l+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="join-ပြီးနောက်-files-မမြင်ရတာဘာကြောင့်လဲ" tabindex="-1">Join ပြီးနောက် Files မမြင်ရတာဘာကြောင့်လဲ? <a class="header-anchor" href="#join-ပြီးနောက်-files-မမြင်ရတာဘာကြောင့်လဲ" aria-label="Permalink to &quot;Join ပြီးနောက် Files မမြင်ရတာဘာကြောင့်လဲ?&quot;">​</a></h3><p>စစ်ပါ:</p><ol><li>အခြား owner က သင့် request ကို approve လုပ်ထားလား။</li><li>အခြား owner က <code>Update Outbound Index</code> နှိပ်ထားလား။</li><li>သင် <code>Update Inbound Index</code> နှိပ်ထားလား။</li><li>အခြား owner ရဲ့ sync folders ထဲ share လုပ်ချင်တဲ့ directories ပါလား။</li></ol><h3 id="domain-change-detected-ဖြစ်ရင်-ဘာလုပ်ရမလဲ" tabindex="-1">Domain Change Detected ဖြစ်ရင် ဘာလုပ်ရမလဲ? <a class="header-anchor" href="#domain-change-detected-ဖြစ်ရင်-ဘာလုပ်ရမလဲ" aria-label="Permalink to &quot;Domain Change Detected ဖြစ်ရင် ဘာလုပ်ရမလဲ?&quot;">​</a></h3><p>admin panel ကို production domain မှဖွင့်ထားလျှင် confirm လုပ်ပြီးဆက်ပါ။</p><p>temporary address သုံးနေပါက cancel လုပ်ပြီး production domain နဲ့ admin panel ကိုပြန်ဖွင့်ကာထပ်ကြိုးစားပါ။</p><h3 id="empty-sync-folder-list-ဆိုတာဘာလဲ" tabindex="-1">Empty Sync Folder List ဆိုတာဘာလဲ? <a class="header-anchor" href="#empty-sync-folder-list-ဆိုတာဘာလဲ" aria-label="Permalink to &quot;Empty Sync Folder List ဆိုတာဘာလဲ?&quot;">​</a></h3><p>sync folder list ဗလာဆိုတာ folders အားလုံး share ဖြစ်တယ်လို့ဆိုလိုပါတယ်။</p><p>directories အချို့ပဲ share ချင်လျှင် အဲဒီ folders တွေကို manually select လုပ်ပါ။</p><h3 id="outbound-နှင့်-inbound-index-updates-ကွာခြားချက်" tabindex="-1">Outbound နှင့် Inbound Index Updates ကွာခြားချက် <a class="header-anchor" href="#outbound-နှင့်-inbound-index-updates-ကွာခြားချက်" aria-label="Permalink to &quot;Outbound နှင့် Inbound Index Updates ကွာခြားချက်&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Simple Meaning</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>အခြားသူများက ကျွန်ုပ်ထံမှ sync လုပ်နိုင်တာကို update လုပ်သည်</td></tr><tr><td>Update Inbound Index</td><td>ကျွန်ုပ်က အခြားသူများထံမှ sync လုပ်ထားတာကို update လုပ်သည်</td></tr></tbody></table>',78)])])}const _=r(h,[["render",b]]);export{k as __pageData,_ as default};
